-- FDB-002C: Import Modeva buildings and unit inventory from reviewed price-list extraction.
-- Source: forever-data/projects/modeva/extracted/price-list.json
-- Import policy: THB currency, 03.07.26 normalized to 2026-07-03, Available normalized to available.

CREATE UNIQUE INDEX IF NOT EXISTS idx_unit_price_history_unique_source
  ON public.unit_price_history(unit_id, price_source, source_file, source_page, price_list_date);

WITH modeva_project AS (
  SELECT id
  FROM public.projects
  WHERE slug = 'modeva'
),
building_source(building_code, name, sort_order, units_count) AS (
  VALUES
    ('A', 'Building A', 1, 56),
    ('B', 'Building B', 2, 8),
    ('C', 'Building C', 3, 38),
    ('D', 'Building D', 4, 71),
    ('E', 'Building E', 5, 18),
    ('F', 'Building F', 6, 76),
    ('G', 'Building G', 7, 22)
),
upsert_buildings AS (
  INSERT INTO public.buildings (
    project_id,
    name,
    building_code,
    building_type,
    floors_count,
    units_count,
    sort_order,
    metadata
  )
  SELECT
    p.id,
    bs.name,
    bs.building_code,
    'residential',
    7,
    bs.units_count,
    bs.sort_order,
    jsonb_build_object(
      'source', 'modeva_price_list',
      'source_file', 'forever-data/projects/modeva/source/price-list/MOB - Price list V.2. - Updated 03.07.2026.pdf',
      'import_task', 'FDB-002C'
    )
  FROM modeva_project p
  CROSS JOIN building_source bs
  ON CONFLICT (project_id, building_code) DO UPDATE SET
    name = EXCLUDED.name,
    building_type = EXCLUDED.building_type,
    floors_count = EXCLUDED.floors_count,
    units_count = EXCLUDED.units_count,
    sort_order = EXCLUDED.sort_order,
    metadata = public.buildings.metadata || EXCLUDED.metadata,
    updated_at = now()
  RETURNING id, project_id, building_code
),
unit_source(
  unit_number,
  building_code,
  floor,
  source_type_code,
  unit_type,
  bedrooms,
  size_sqm,
  price,
  price_per_sqm,
  availability_status,
  source_file,
  source_page,
  source_row,
  raw_metadata
) AS (
