),
resolved_units AS (
  SELECT
    p.id AS project_id,
    b.id AS building_id,
    us.*,
    us.raw_metadata::jsonb AS metadata_json
  FROM unit_source us
  JOIN modeva_project p ON true
  JOIN upsert_buildings b
    ON b.project_id = p.id
   AND b.building_code = us.building_code
  WHERE us.unit_number IS NOT NULL
    AND us.building_code IS NOT NULL
    AND us.floor IS NOT NULL
    AND us.unit_type IS NOT NULL
    AND us.bedrooms IS NOT NULL
    AND us.size_sqm IS NOT NULL
    AND us.price IS NOT NULL
    AND us.availability_status IS NOT NULL
),
updated_units AS (
  UPDATE public.units u
  SET
    building_id = ru.building_id,
    unit_type = ru.unit_type,
    bedrooms = ru.bedrooms,
    size_sqm = ru.size_sqm,
    floor = ru.floor,
    base_price_thb = ru.price,
    price_per_sqm = ru.price_per_sqm,
    availability_status = ru.availability_status,
    unit_status = ru.availability_status,
    metadata = COALESCE(u.metadata, '{}'::jsonb) || jsonb_build_object(
      'source_type_code', ru.source_type_code,
      'currency', 'THB',
      'price_source', 'developer_price_list',
      'source_file', ru.source_file,
      'source_page', ru.source_page,
      'source_row', ru.source_row,
      'price_list_date', '2026-07-03',
      'raw', ru.metadata_json
    ),
    updated_at = now()
  FROM resolved_units ru
  WHERE u.project_id = ru.project_id
    AND u.unit_code = ru.unit_number
  RETURNING u.id, u.unit_code
),
inserted_units AS (
  INSERT INTO public.units (
    project_id,
    building_id,
    unit_code,
    unit_type,
    bedrooms,
    bathrooms,
    size_sqm,
    floor,
    base_price_thb,
    price_per_sqm,
    availability_status,
    unit_status,
    metadata
  )
  SELECT
    ru.project_id,
    ru.building_id,
    ru.unit_number,
    ru.unit_type,
    ru.bedrooms,
    NULL,
    ru.size_sqm,
    ru.floor,
    ru.price,
    ru.price_per_sqm,
    ru.availability_status,
    ru.availability_status,
    jsonb_build_object(
      'source_type_code', ru.source_type_code,
      'currency', 'THB',
      'price_source', 'developer_price_list',
      'source_file', ru.source_file,
      'source_page', ru.source_page,
      'source_row', ru.source_row,
      'price_list_date', '2026-07-03',
      'raw', ru.metadata_json
    )
  FROM resolved_units ru
  WHERE NOT EXISTS (
    SELECT 1
    FROM public.units existing
    WHERE existing.project_id = ru.project_id
      AND existing.unit_code = ru.unit_number
  )
  RETURNING id, unit_code
),
affected_units AS (
  SELECT id, unit_code
  FROM updated_units
  UNION ALL
  SELECT id, unit_code
  FROM inserted_units
),
price_rows AS (
  SELECT
    au.id AS unit_id,
    ru.price,
    'THB'::TEXT AS currency,
    'developer_price_list'::TEXT AS price_source,
    ru.source_file,
    ru.source_page,
    '2026-07-03'::DATE AS price_list_date,
    jsonb_build_object(
      'source_type_code', ru.source_type_code,
      'unit_number', ru.unit_number,
      'building_code', ru.building_code,
      'floor', ru.floor,
      'unit_type', ru.unit_type,
      'bedrooms', ru.bedrooms,
      'size_sqm', ru.size_sqm,
      'price_per_sqm', ru.price_per_sqm,
      'availability_status', ru.availability_status,
      'source_row', ru.source_row,
      'raw', ru.metadata_json
    ) AS metadata
  FROM resolved_units ru
  JOIN affected_units au ON au.unit_code = ru.unit_number
)
INSERT INTO public.unit_price_history (
  unit_id,
  price,
  currency,
  price_source,
  source_file,
  source_page,
  recorded_at,
  price_list_date,
  metadata
)
SELECT
  unit_id,
  price,
  currency,
  price_source,
  source_file,
  source_page,
  now(),
  price_list_date,
  metadata
FROM price_rows
ON CONFLICT (unit_id, price_source, source_file, source_page, price_list_date) DO UPDATE SET
  price = EXCLUDED.price,
  currency = EXCLUDED.currency,
  recorded_at = EXCLUDED.recorded_at,
  metadata = EXCLUDED.metadata,
  updated_at = now();
